3_real_world_example.code:
const counter = {
  count: 0,
  increment() {
    // We must use 'this' to reach the sibling property
    this.count++;
    console.log(this.count);
  }
};

counter.increment(); // 1
counter.increment(); // 2

6_edge_case.code:
const game = {
  player: {
    name: 'Mario',
    jump() { console.log(this === game.player); }
  }
};
game.player.jump(); // true. 'this' is 'player', NOT 'game'.
